#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAXN 10
#define MAXPATHS 10000
#define MAXLEN 100

int grid[MAXN][MAXN];
int visited[MAXN][MAXN];
char paths[MAXPATHS][MAXLEN];
int pathCount;

int isValid(int x, int y, int n) {
    return (x >= 0 && x < n && y >= 0 && y < n && grid[x][y] == 1 && visited[x][y] == 0);
}

void dfs(int x, int y, int n, char *path) {
    if (x == n - 1 && y == n - 1) {
        strcpy(paths[pathCount++], path);
        return;
    }
    visited[x][y] = 1;
    int len = strlen(path);
    if (len >= MAXLEN - 1) {
        visited[x][y] = 0;
        return;
    }
    if (isValid(x + 1, y, n)) {
        path[len] = 'D';
        path[len + 1] = '\0';
        dfs(x + 1, y, n, path);
        path[len] = '\0';
    }
    if (isValid(x, y - 1, n)) {
        path[len] = 'L';
        path[len + 1] = '\0';
        dfs(x, y - 1, n, path);
        path[len] = '\0';
    }
    if (isValid(x, y + 1, n)) {
        path[len] = 'R';
        path[len + 1] = '\0';
        dfs(x, y + 1, n, path);
        path[len] = '\0';
    }
    if (isValid(x - 1, y, n)) {
        path[len] = 'U';
        path[len + 1] = '\0';
        dfs(x - 1, y, n, path);
        path[len] = '\0';
    }
    visited[x][y] = 0;
}

int compareStrings(const void *a, const void *b) {
    return strcmp((char *)a, (char *)b);
}

char **findAllPaths(int n, int *returnSize) {
    memset(visited, 0, sizeof(visited));
    pathCount = 0;
    if (grid[0][0] == 0) {
        *returnSize = 0;
        return NULL;
    }
    char path[MAXLEN] = "";
    dfs(0, 0, n, path);
    *returnSize = pathCount;
    if (pathCount == 0)
        return NULL;
    qsort(paths, pathCount, sizeof(paths[0]), compareStrings);
    char **result = malloc(pathCount * sizeof(char *));
    for (int i = 0; i < pathCount; i++) {
        result[i] = strdup(paths[i]);
    }
    return result;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                scanf("%d", &grid[i][j]);
            }
        }
        int returnSize;
        char **paths = findAllPaths(n, &returnSize);
        if (returnSize == 0) {
            printf("-1\n");
        } else {
            for (int i = 0; i < returnSize; i++) {
                printf("%s\n", paths[i]);
            }
        }
    }
    return 0;
}

