#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
using namespace std;

vector<string> findAllPaths(int n, vector<vector<int>>& grid) {
    vector<string> ans;
    vector<vector<int>> visited(n, vector<int>(n, 0));

    bool isValid(int x, int y, int n, vector<vector<int>>& grid) {
        return (x >= 0 && x < n && y >= 0 && y < n && grid[x][y] == 1 && visited[x][y] == 0);
    }

    void dfs(int x, int y, int n, vector<vector<int>>& grid, string path) {
        if (x == n - 1 && y == n - 1) {
            ans.push_back(path);
            return;
        }
        visited[x][y] = 1;
        if (isValid(x + 1, y, n, grid))
            dfs(x + 1, y, n, grid, path + 'D');
        if (isValid(x, y - 1, n, grid))
            dfs(x, y - 1, n, grid, path + 'L');
        if (isValid(x, y + 1, n, grid))
            dfs(x, y + 1, n, grid, path + 'R');
        if (isValid(x - 1, y, n, grid))
            dfs(x - 1, y, n, grid, path + 'U');
        visited[x][y] = 0;
    }

    if (grid[0][0] == 0)
        return {};
    dfs(0, 0, n, grid, "");
    sort(ans.begin(), ans.end());
    return ans;
}

int main() {
    int T;
    cin >> T;
    while (T--) {
        int n;
        cin >> n;
        vector<vector<int>> grid(n, vector<int>(n));
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                cin >> grid[i][j];
            }
        }
        vector<string> paths = findAllPaths(n, grid);
        if (paths.empty()) {
            cout << -1 << endl;
        } else {
            for (const auto& path : paths) {
                cout << path << endl;
            }
        }
    }
    return 0;
}

